import sys
def is_double(s):
    half=len(s)//2
    return s[:half]==s[half:]

def can_delete_left(s):
    n=len(s)
    half=(n-1)//2
    i,j=0,half+1
    skipped=False
    while i<half+1 and j<n:
        if s[i]==s[j]:
            i+=1;j+=1
        elif not skipped:
            skipped=True;i+=1
        else:
            return False
    return True

def can_delete_right(s):
    n=len(s)
    half=(n-1)//2
    i,j=0,half
    skipped=False
    while i<half and j<n:
        if s[i]==s[j]:
            i+=1;j+=1
        elif not skipped:
            skipped=True;j+=1
        else:
            return False
    return True

def is_special(s):
    n=len(s)
    if n==1:
        return False
    if n%2==0:
        return is_double(s)
    return can_delete_left(s) or can_delete_right(s)

def main():
    data=sys.stdin.read().splitlines()
    if not data:
        return
    D=int(data[0])
    out=[]
    for i in range(1,D+1):
        s=data[i].strip()
        out.append('YES' if is_special(s) else 'NO')
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    main()
